+// ─── Day/Night Cycle and Visual Theme ───────────────────────────────
+
+/**
+ * Returns the current time of day as a string: 'day', 'dusk', 'night', 'dawn'.
+ * Uses system time hours to determine phase.
+ */
+export function getTimeOfDay(): 'day' | 'dusk' | 'night' | 'dawn' {
+  const hour = new Date().getHours();
+  if (hour >= 6 && hour < 18) return 'day';
+  if (hour >= 18 && hour < 20) return 'dusk';
+  if (hour >= 20 || hour < 4) return 'night';
+  return 'dawn';
+}
+
+/**
+ * Applies a visual theme overlay on the canvas context based on time of day.
+ * Adjusts overlay color and opacity to simulate lighting and color temperature.
+ * At night, torch light is more prominent (handled by torch drawing).
+ * @param ctx CanvasRenderingContext2D to draw overlay on
+ * @param width Width of canvas
+ * @param height Height of canvas
+ */
+export function applyTimeTheme(ctx: CanvasRenderingContext2D, width: number, height: number) {
+  const time = getTimeOfDay();
+  let overlayColor = '';
+  let overlayAlpha = 0;
+
+  switch (time) {
+    case 'day':
+      // Slight warm tint for day
+      overlayColor = 'rgba(255, 244, 214, 0.05)';
+      overlayAlpha = 0.05;
+      break;
+    case 'dusk':
+      // Orange dusk tint
+      overlayColor = 'rgba(255, 140, 60, 0.15)';
+      overlayAlpha = 0.15;
+      break;
+    case 'night':
+      // Dark blue night tint
+      overlayColor = 'rgba(10, 20, 40, 0.5)';
+      overlayAlpha = 0.5;
+      break;
+    case 'dawn':
+      // Soft pink dawn tint
+      overlayColor = 'rgba(255, 180, 160, 0.1)';
+      overlayAlpha = 0.1;
+      break;
+  }
+
+  if (overlayAlpha > 0) {
+    ctx.save();
+    ctx.fillStyle = overlayColor;
+    ctx.fillRect(0, 0, width, height);
+    ctx.restore();
+  }
+}
+
